import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        b = sorted(a)
        i = 0
        for x in a:
            if i < N and x == b[i]:
                i += 1
        out_lines.append(str(N - i))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

